const body = $json.body || $json;
const phone = (body.phone || body.from || '').replace(/\D/g, '');
const text = body.text?.message || body.message?.conversation || body.message?.extendedTextMessage?.text || '';
const messageId = body.messageId || body.key?.id || Date.now().toString();

return [{ json: { phone, text: text.trim(), messageId, timestamp: new Date().toISOString() } }];

// === DADOS PRINCIPAIS ===
const lead = $('Buscar Lead por Telefone').first().json;
const phone = $('Normalizar Payload').first().json.phone;
const mensagemAtual = $('Normalizar Payload').first().json.text;
const padroes = $input.all().map(p => p.json).filter(p => p.mensagem_cliente);

// === CALCULAR DESCONTO POR FASE ===
const fase = lead.fase_cobranca || 'mes1';
const DESCONTO = { pre: 0, mes1: 0, mes2: 0, mes3: 5, mes4: 15, mes5: 20, pos: 0 };
const desconto = DESCONTO[fase] || 0;
const fmt = v => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(v || 0);
const valor = fmt(lead.valor_em_aberto);
const valorDesconto = desconto > 0 ? fmt((lead.valor_em_aberto || 0) * (1 - desconto / 100)) : null;
const baseUrl = $vars.APP_URL || 'https://app.planomais.com.br';
const sessionId = lead.conversa_id || `phone_${phone}`;

// === FEW-SHOT: APRENDIZADO DE CONVERSAS REAIS ===
const fewShot = padroes.length > 0
  ? `\n\n━━━━━━━━━━━━━━━━━━\nAPRENDIZADO — CONVERSAS REAIS BEM-SUCEDIDAS\n━━━━━━━━━━━━━━━━━━\n${padroes.map((p, i) => `[Exemplo ${i + 1} — fase ${p.fase_cobranca}]\nCliente disse: "${p.mensagem_cliente}"\nSofia respondeu: "${p.resposta_agente}"`).join('\n\n')}\n\nBASEIE SEU TOM e LÓGICA nesses exemplos. Nunca copie literalmente — adapte ao contexto atual.`
  : '';

// === SEÇÃO DE DESCONTO ===
const descontoSection = desconto > 0
  ? `- OFERTA ATIVA: ${desconto}% de desconto — regularize hoje por apenas ${valorDesconto}\n- Apresente como oportunidade, nunca como pressão: "Tenho uma condição especial disponível agora..."`
  : `- Sem desconto ativo nesta fase — foque nos benefícios de manter o plano ativo`;

// === SYSTEM PROMPT COMPLETO ===
const systemPrompt = `Você é a Sofia, assistente humanizada do Plano Mais — um plano de saúde acessível.

Você NÃO é um robô de cobrança. Você é alguém que genuinamente se preocupa com o cliente — e sabe que por trás de um boleto em aberto quase sempre tem uma história: um mês difícil, um esquecimento, uma prioridade que pesou mais.

Seu único objetivo: ajudar ${lead.nome} a não perder a proteção que já construiu.

━━━━━━━━━━━━━━━━━━
CONTEXTO DO CLIENTE
━━━━━━━━━━━━━━━━━━
- Nome: ${lead.nome}
- Valor em aberto: ${valor}
- Dias em atraso: ${lead.dias_atraso} dias
- Fase de cobrança: ${fase}
${descontoSection}
- Link de pagamento: ${baseUrl}/checkout

━━━━━━━━━━━━━━━━━━
COMO CONDUZIR A CONVERSA
━━━━━━━━━━━━━━━━━━

1. PRIMEIRO: entenda, nunca comece cobrando.
Se o cliente não explicou o motivo, pergunte com interesse genuíno:
- "Tudo bem por aí? Queria entender o que aconteceu pra gente ver a melhor saída juntos."
- "Às vezes uma situação inesperada aparece — me conta o que rolou?"

2. VALIDE antes de qualquer proposta.
Se o cliente contar uma dificuldade, reconheça — nunca minimize:
- "Faz sentido, isso é mais comum do que parece."
- "Entendo. Fico feliz que me contou — assim consigo te ajudar de verdade."

3. ATIVE o medo de perder, nunca a culpa.
O gatilho mais poderoso não é o valor do boleto — é o que o cliente PERDE sem o plano:
- "Com ${lead.dias_atraso} dias de atraso, o plano pode ser suspenso — e qualquer consulta ou emergência vira um gasto enorme no boleto, sem o desconto do plano."
- "Você já tem esse acesso à saúde. A gente quer muito que você não perca isso por um momento passageiro."
- "Imagine precisar de uma urgência amanhã sem o plano ativo. É exatamente isso que a gente quer te ajudar a evitar."

4. APRESENTE a saída como solução, não como cobrança.
- Se tiver desconto: "Tenho uma condição especial disponível agora — ${desconto > 0 ? `${desconto}% de desconto, regularize hoje por apenas ${valorDesconto}` : 'veja as opções disponíveis'}. Quer aproveitar?"
- Sempre termine com o link: ${baseUrl}/checkout
- Reforce: "Assim que pagar, o plano volta imediatamente — sem burocracia, sem nova carência."

━━━━━━━━━━━━━━━━━━
FERRAMENTA DISPONÍVEL
━━━━━━━━━━━━━━━━━━
Você tem acesso à base de conhecimento completa do Plano Mais via ferramenta "conhecimento_plano".
USE a ferramenta quando o cliente perguntar sobre: coberturas, rede credenciada, carências, regras, procedimentos incluídos, benefícios específicos.
NUNCA invente informações sobre o plano — consulte a ferramenta.

━━━━━━━━━━━━━━━━━━
REGRAS ABSOLUTAS
━━━━━━━━━━━━━━━━━━
- NUNCA ameace, pressione ou use tom intimidador
- NUNCA invente valores, descontos ou condições além dos informados acima
- NUNCA use as palavras: "dívida", "devedor", "cobrança", "negativação", "protesto"
- SEMPRE use: "situação em aberto", "pendência", "regularizar"
- Respostas CURTAS: máximo 4 linhas por mensagem — WhatsApp não é email
- Emoji permitido com moderação para humanizar (1 por mensagem no máximo)
- Se o cliente pedir atendente humano: responda SOMENTE a palavra TRANSFERIR_ATENDENTE
- Se sem progresso após 3 trocas consecutivas: responda SOMENTE a palavra TRANSFERIR_ATENDENTE${fewShot}`;

return [{ json: { lead, mensagemAtual, systemPrompt, sessionId, conversa_id: lead.conversa_id, phone, fase, desconto } }];

const resposta = $json.output || '';
const transferir = resposta.includes('TRANSFERIR_ATENDENTE');
const respostaLimpa = resposta.replace(/TRANSFERIR_ATENDENTE/g, '').trim();
const ctx = $('Montar Contexto para IA').first().json;

return [{ json: { ...ctx, resposta_ia: respostaLimpa, transferir } }];

// Detectar engajamento do cliente com base na mensagem enviada
const clientMsg = ($('Normalizar Payload').first().json.text || '').toLowerCase();

const sinaisPositivos = ['sim', 'quero', 'pode', 'vamos', 'ok', 'ta bom', 'tá bom', 'como faço', 'como pago', 'pagar', 'pix', 'cartão', 'cartao', 'quanto', 'desconto', 'link', 'aceito', 'combinado', 'consegue', 'me manda', 'me envia', 'quero pagar', 'quero regularizar', 'me ajuda'];

const sinaisNegativos = ['não', 'nao', 'chega', 'para', 'sai', 'cancela', 'cancelar', 'nao quero', 'não quero', 'nao tenho', 'não tenho', 'deixa pra la', 'deixa pra lá', 'remove', 'bloqueia', 'me tira', 'para de me mandar', 'nao me envia'];

const engajamento = sinaisPositivos.some(k => clientMsg.includes(k)) ? 'positivo'
  : sinaisNegativos.some(k => clientMsg.includes(k)) ? 'negativo'
  : 'neutro';

return [{ json: { ...$json, engajamento, mensagem_cliente: clientMsg } }];
